package com.enterprise.saml.model;

import java.io.Serializable;
import java.security.Principal;
import java.time.Instant;
import java.util.*;

public class SamlUserPrincipal implements Principal, Serializable {
    private static final long serialVersionUID = 1L;

    private String nameId;
    private String nameIdFormat;
    private String sessionIndex;
    private Instant authenticationInstant;
    private Map<String, List<String>> attributes;
    private String issuer;

    public SamlUserPrincipal() {
        this.attributes = new HashMap<>();
    }

    @Override
    public String getName() {
        return nameId;
    }

    public String getNameId() { return nameId; }
    public void setNameId(String nameId) { this.nameId = nameId; }
    public String getNameIdFormat() { return nameIdFormat; }
    public void setNameIdFormat(String nameIdFormat) { this.nameIdFormat = nameIdFormat; }
    public String getSessionIndex() { return sessionIndex; }
    public void setSessionIndex(String sessionIndex) { this.sessionIndex = sessionIndex; }
    public Instant getAuthenticationInstant() { return authenticationInstant; }
    public void setAuthenticationInstant(Instant authenticationInstant) { this.authenticationInstant = authenticationInstant; }
    public Map<String, List<String>> getAttributes() { return attributes; }
    public void setAttributes(Map<String, List<String>> attributes) { this.attributes = attributes; }
    public String getIssuer() { return issuer; }
    public void setIssuer(String issuer) { this.issuer = issuer; }

    public String getFirstAttribute(String name) {
        List<String> values = attributes.get(name);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }

    public void addAttribute(String name, String value) {
        attributes.computeIfAbsent(name, k -> new ArrayList<>()).add(value);
    }

    public String getEmail() {
        return getFirstAttribute("email") != null ? getFirstAttribute("email") :
               getFirstAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress");
    }

    public String getFirstName() {
        return getFirstAttribute("firstName") != null ? getFirstAttribute("firstName") :
               getFirstAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname");
    }

    public String getLastName() {
        return getFirstAttribute("lastName") != null ? getFirstAttribute("lastName") :
               getFirstAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname");
    }

    public List<String> getRoles() {
        List<String> roles = attributes.get("roles");
        if (roles == null) {
            roles = attributes.get("http://schemas.microsoft.com/ws/2008/06/identity/claims/role");
        }
        return roles != null ? roles : Collections.emptyList();
    }

    @Override
    public String toString() {
        return "SamlUserPrincipal{nameId='" + nameId + "', attributes=" + attributes.keySet() + "}";
    }
}

// ==================== SAML Authentication Token ====================

package com.enterprise.saml.security;

import com.enterprise.saml.model.SamlUserPrincipal;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;

import java.util.Collection;
import java.util.stream.Collectors;

public class SamlAuthenticationToken extends AbstractAuthenticationToken {
    private final SamlUserPrincipal principal;
    private final String samlResponse;

    public SamlAuthenticationToken(SamlUserPrincipal principal, String samlResponse, Collection<? extends GrantedAuthority> authorities) {
        super(authorities);
        this.principal = principal;
        this.samlResponse = samlResponse;
        setAuthenticated(true);
    }

    public static SamlAuthenticationToken fromPrincipal(SamlUserPrincipal principal, String samlResponse) {
        Collection<GrantedAuthority> authorities = principal.getRoles().stream()
                .map(role -> new SimpleGrantedAuthority("ROLE_" + role.toUpperCase()))
                .collect(Collectors.toList());

        if (authorities.isEmpty()) {
            authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
        }

        return new SamlAuthenticationToken(principal, samlResponse, authorities);
    }

    @Override
    public Object getCredentials() {
        return samlResponse;
    }

    @Override
    public SamlUserPrincipal getPrincipal() {
        return principal;
    }
}

// ==================== XML Signature Validator ====================

package com.enterprise.saml.security;

import com.enterprise.saml.config.SamlProperties;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;

import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.*;
import java.io.FileInputStream;
import java.io.InputStream;
import java.security.PublicKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;

@Component
public class XmlSignatureValidator {
    private static final Logger logger = LoggerFactory.getLogger(XmlSignatureValidator.class);

    private final SamlProperties samlProperties;
    private X509Certificate idpCertificate;

    public XmlSignatureValidator(SamlProperties samlProperties) {
        this.samlProperties = samlProperties;
    }

    public void init() throws Exception {
        if (samlProperties.getIdpCertificatePath() != null) {
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            try (InputStream is = new FileInputStream(samlProperties.getIdpCertificatePath())) {
                idpCertificate = (X509Certificate) cf.generateCertificate(is);
            }
            logger.info("Loaded IdP certificate: {}", idpCertificate.getSubjectX500Principal());
        }
    }

    public X509Certificate getIdpCertificate() throws Exception {
        if (idpCertificate == null) {
            init();
        }
        return idpCertificate;
    }

    public boolean validateSignature(Document document) {
        try {
            NodeList signatureNodes = document.getElementsByTagNameNS(XMLSignature.XMLNS, "Signature");
            if (signatureNodes.getLength() == 0) {
                logger.warn("No XML Signature found in the document");
                return false;
            }

            X509Certificate cert = getIdpCertificate();
            if (cert == null) {
                logger.error("No IdP certificate configured for signature validation");
                return false;
            }

            PublicKey publicKey = cert.getPublicKey();

            for (int i = 0; i < signatureNodes.getLength(); i++) {
                DOMValidateContext validateContext = new DOMValidateContext(publicKey, signatureNodes.item(i));
                validateContext.setIdAttributeNS(
                    document.getDocumentElement(),
                    null, "ID"
                );

                // Set ID attributes on assertions too
                NodeList assertions = document.getElementsByTagNameNS(
                    "urn:oasis:names:tc:SAML:2.0:assertion", "Assertion");
                for (int j = 0; j < assertions.getLength(); j++) {
                    validateContext.setIdAttributeNS(
                        (org.w3c.dom.Element) assertions.item(j),
                        null, "ID"
                    );
                }

                XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
                XMLSignature signature = factory.unmarshalXMLSignature(validateContext);

                boolean valid = signature.validate(validateContext);
                if (!valid) {
                    logger.error("XML Signature validation failed for signature #{}", i);

                    // Detailed validation for debugging
                    boolean signatureValueValid = signature.getSignatureValue().validate(validateContext);
                    logger.debug("Signature value valid: {}", signatureValueValid);

                    for (Reference ref : signature.getSignedInfo().getReferences()) {
                        boolean refValid = ref.validate(validateContext);
                        logger.debug("Reference '{}' valid: {}", ref.getURI(), refValid);
                    }

                    return false;
                }
            }

            logger.info("XML Signature validation successful");
            return true;

        } catch (Exception e) {
            logger.error("Error validating XML Signature", e);
            return false;
        }
    }
}

// ==================== SAML Response Parser ====================

package com.enterprise.saml.service;

import com.enterprise.saml.config.SamlProperties;
import com.enterprise.saml.model.SamlUserPrincipal;
import com.enterprise.saml.security.XmlSignatureValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.StringReader;
import java.time.Instant;
import java.time.format.DateTimeParseException;
import java.util.Base64;

@Service
public class SamlResponseParser {
    private static final Logger logger = LoggerFactory.getLogger(SamlResponseParser.class);

    private static final String SAML2_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String SAML2_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String STATUS_SUCCESS = "urn:oasis:names:tc:SAML:2.0:status:Success";

    private final SamlProperties samlProperties;
    private final XmlSignatureValidator signatureValidator;

    public SamlResponseParser(SamlProperties samlProperties, XmlSignatureValidator signatureValidator) {
        this.samlProperties = samlProperties;
        this.signatureValidator = signatureValidator;
    }

    public SamlUserPrincipal parseSamlResponse(String encodedResponse) throws SamlProcessingException {
        try {
            // Decode Base64 SAML Response
            byte[] decodedBytes = Base64.getDecoder().decode(encodedResponse);
            String samlXml = new String(decodedBytes, "UTF-8");
            logger.debug("Decoded SAML Response XML");

            // Parse XML securely
            Document document = parseXmlSecurely(samlXml);

            // Validate response structure
            validateResponseStructure(document);

            // Validate XML Signature
            if (!signatureValidator.validateSignature(document)) {
                throw new SamlProcessingException("SAML Response signature validation failed");
            }

            // Validate response status
            validateResponseStatus(document);

            // Validate conditions
            validateConditions(document);

            // Extract assertion and build user principal
            return extractUserPrincipal(document);

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            logger.error("Failed to parse SAML response", e);
            throw new SamlProcessingException("Failed to parse SAML response: " + e.getMessage(), e);
        }
    }

    private Document parseXmlSecurely(String xml) throws SamlProcessingException {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);

            // Prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new InputSource(new StringReader(xml)));
            document.getDocumentElement().normalize();

            return document;
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to parse SAML XML securely", e);
        }
    }

    private void validateResponseStructure(Document document) throws SamlProcessingException {
        Element root = document.getDocumentElement();

        if (!"Response".equals(root.getLocalName()) ||
            !SAML2_PROTOCOL_NS.equals(root.getNamespaceURI())) {
            throw new SamlProcessingException("Invalid SAML Response: root element is not samlp:Response");
        }

        // Validate Destination
        String destination = root.getAttribute("Destination");
        if (destination != null && !destination.isEmpty() &&
            !destination.equals(samlProperties.getAcsUrl())) {
            throw new SamlProcessingException("SAML Response destination mismatch. Expected: " +
                samlProperties.getAcsUrl() + ", Got: " + destination);
        }

        // Validate IssueInstant is not too old
        String issueInstantStr = root.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            try {
                Instant issueInstant = Instant.parse(issueInstantStr);
                Instant now = Instant.now();
                long skewSeconds = samlProperties.getResponseSkewTime();

                if (issueInstant.isBefore(now.minusSeconds(samlProperties.getMaxAuthenticationAge()))) {
                    throw new SamlProcessingException("SAML Response is too old");
                }
                if (issueInstant.isAfter(now.plusSeconds(skewSeconds))) {
                    throw new SamlProcessingException("SAML Response IssueInstant is in the future");
                }
            } catch (DateTimeParseException e) {
                throw new SamlProcessingException("Invalid IssueInstant format", e);
            }
        }

        // Validate Issuer
        NodeList issuerNodes = root.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            String issuer = issuerNodes.item(0).getTextContent().trim();
            if (samlProperties.getIdpEntityId() != null &&
                !samlProperties.getIdpEntityId().equals(issuer)) {
                throw new SamlProcessingException("SAML Response issuer mismatch. Expected: " +
                    samlProperties.getIdpEntityId() + ", Got: " + issuer);
            }
        }
    }

    private void validateResponseStatus(Document document) throws SamlProcessingException {
        Element root = document.getDocumentElement();
        NodeList statusNodes = root.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "Status");

        if (statusNodes.getLength() == 0) {
            throw new SamlProcessingException("SAML Response missing Status element");
        }

        Element statusElement = (Element) statusNodes.item(0);
        NodeList statusCodeNodes = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");

        if (statusCodeNodes.getLength() == 0) {
            throw new SamlProcessingException("SAML Response missing StatusCode element");
        }

        String statusCode = ((Element) statusCodeNodes.item(0)).getAttribute("Value");
        if (!STATUS_SUCCESS.equals(statusCode)) {
            // Try to get status message for better error reporting
            String statusMessage = "";
            NodeList messageNodes = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusMessage");
            if (messageNodes.getLength() > 0) {
                statusMessage = messageNodes.item(0).getTextContent();
            }
            throw new SamlProcessingException("SAML authentication failed. Status: " + statusCode +
                (statusMessage.isEmpty() ? "" : ", Message: " + statusMessage));
        }
    }

    private void validateConditions(Document document) throws SamlProcessingException {
        NodeList conditionsNodes = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");

        if (conditionsNodes.getLength() == 0) {
            logger.warn("No Conditions element found in SAML assertion");
            return;
        }

        Element conditions = (Element) conditionsNodes.item(0);
        Instant now = Instant.now();
        long skewSeconds = samlProperties.getResponseSkewTime();

        // Check NotBefore
        String notBeforeStr = conditions.getAttribute("NotBefore");
        if (notBeforeStr != null && !notBeforeStr.isEmpty()) {
            try {
                Instant notBefore = Instant.parse(notBeforeStr);
                if (now.plusSeconds(skewSeconds).isBefore(notBefore)) {
                    throw new SamlProcessingException("SAML assertion is not yet valid. NotBefore: " + notBeforeStr);
                }
            } catch (DateTimeParseException e) {
                throw new SamlProcessingException("Invalid NotBefore format", e);
            }
        }

        // Check NotOnOrAfter
        String notOnOrAfterStr = conditions.getAttribute("NotOnOrAfter");
        if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
            try {
                Instant notOnOrAfter = Instant.parse(notOnOrAfterStr);
                if (now.minusSeconds(skewSeconds).isAfter(notOnOrAfter) || now.minusSeconds(skewSeconds).equals(notOnOrAfter)) {
                    throw new SamlProcessingException("SAML assertion has expired. NotOnOrAfter: " + notOnOrAfterStr);
                }
            } catch (DateTimeParseException e) {
                throw new SamlProcessingException("Invalid NotOnOrAfter format", e);
            }
        }

        // Validate AudienceRestriction
        NodeList audienceRestrictions = conditions.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AudienceRestriction");
        if (audienceRestrictions.getLength() > 0) {
            boolean audienceMatch = false;
            Element audienceRestriction = (Element) audienceRestrictions.item(0);
            NodeList audiences = audienceRestriction.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Audience");

            for (int i = 0; i < audiences.getLength(); i++) {
                String audience = audiences.item(i).getTextContent().trim();
                if (samlProperties.getEntityId().equals(audience)) {
                    audienceMatch = true;
                    break;
                }
            }

            if (!audienceMatch) {
                throw new SamlProcessingException("SAML assertion audience does not match SP entity ID: " +
                    samlProperties.getEntityId());
            }
        }
    }

    private SamlUserPrincipal extractUserPrincipal(Document document) throws SamlProcessingException {
        NodeList assertionNodes = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");

        if (assertionNodes.getLength() == 0) {
            throw new SamlProcessingException("No Assertion found in SAML Response");
        }

        Element assertion = (Element) assertionNodes.item(0);
        SamlUserPrincipal principal = new SamlUserPrincipal();

        // Extract Issuer
        NodeList issuerNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            principal.setIssuer(issuerNodes.item(0).getTextContent().trim());
        }

        // Extract Subject / NameID
        extractSubject(assertion, principal);

        // Extract AuthnStatement
        extractAuthnStatement(assertion, principal);

        // Extract Attributes
        extractAttributes(assertion, principal);

        logger.info("Successfully extracted SAML principal: {}", principal.getNameId());
        return principal;
    }

    private void extractSubject(Element assertion, SamlUserPrincipal principal) throws SamlProcessingException {
        NodeList subjectNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");

        if (subjectNodes.getLength() == 0) {
            throw new SamlProcessingException("No Subject found in SAML Assertion");
        }

        Element subject = (Element) subjectNodes.item(0);

        // Extract NameID
        NodeList nameIdNodes = subject.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() > 0) {
            Element nameIdElement = (Element) nameIdNodes.item(0);
            principal.setNameId(nameIdElement.getTextContent().trim());
            String format = nameIdElement.getAttribute("Format");
            if (format != null && !format.isEmpty()) {
                principal.setNameIdFormat(format);
            }
        } else {
            throw new SamlProcessingException("No NameID found in SAML Subject");
        }

        // Validate SubjectConfirmation
        NodeList confirmationNodes = subject.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmation");
        if (confirmationNodes.getLength() > 0) {
            Element confirmation = (Element) confirmationNodes.item(0);
            String method = confirmation.getAttribute("Method");

            if ("urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(method)) {
                NodeList confirmationDataNodes = confirmation.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "SubjectConfirmationData");

                if (confirmationDataNodes.getLength() > 0) {
                    Element confirmationData = (Element) confirmationDataNodes.item(0);

                    // Check Recipient
                    String recipient = confirmationData.getAttribute("Recipient");
                    if (recipient != null && !recipient.isEmpty() &&
                        !recipient.equals(samlProperties.getAcsUrl())) {
                        throw new SamlProcessingException("SubjectConfirmationData Recipient mismatch");
                    }

                    // Check NotOnOrAfter
                    String notOnOrAfterStr = confirmationData.getAttribute("NotOnOrAfter");
                    if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                        try {
                            Instant notOnOrAfter = Instant.parse(notOnOrAfterStr);
                            if (Instant.now().isAfter(notOnOrAfter)) {
                                throw new SamlProcessingException("SubjectConfirmation has expired");
                            }
                        } catch (DateTimeParseException e) {
                            logger.warn("Could not parse SubjectConfirmationData NotOnOrAfter", e);
                        }
                    }
                }
            }
        }
    }

    private void extractAuthnStatement(Element assertion, SamlUserPrincipal principal) {
        NodeList authnStatementNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");

        if (authnStatementNodes.getLength() > 0) {
            Element authnStatement = (Element) authnStatementNodes.item(0);

            // Session Index
            String sessionIndex = authnStatement.getAttribute("SessionIndex");
            if (sessionIndex != null && !sessionIndex.isEmpty()) {
                principal.setSessionIndex(sessionIndex);
            }

            // AuthnInstant
            String authnInstantStr = authnStatement.getAttribute("AuthnInstant");
            if (authnInstantStr != null && !authnInstantStr.isEmpty()) {
                try {
                    principal.setAuthenticationInstant(Instant.parse(authnInstantStr));
                } catch (DateTimeParseException e) {
                    logger.warn("Could not parse AuthnInstant: {}", authnInstantStr);
                }
            }
        }
    }

    private void extractAttributes(Element assertion, SamlUserPrincipal principal) {
        NodeList attributeStatementNodes = assertion.getElementsByTagNameNS(
            SAML2_ASSERTION_NS, "AttributeStatement");

        if (attributeStatementNodes.getLength() == 0) {
            logger.info("No AttributeStatement found in SAML Assertion");
            return;
        }

        Element attributeStatement = (Element) attributeStatementNodes.item(0);
        NodeList attributeNodes = attributeStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");

        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attribute = (Element) attributeNodes.item(i);
            String attributeName = attribute.getAttribute("Name");
            String friendlyName = attribute.getAttribute("FriendlyName");

            NodeList valueNodes = attribute.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeValue");
            for (int j = 0; j < valueNodes.getLength(); j++) {
                String value = valueNodes.item(j).getTextContent().trim();
                if (!value.isEmpty()) {
                    principal.addAttribute(attributeName, value);
                    // Also store by friendly name if available
                    if (friendlyName != null && !friendlyName.isEmpty()) {
                        principal.addAttribute(friendlyName, value);
                    }
                }
            }

            logger.debug("Extracted SAML attribute: {} = {} value(s)", attributeName, valueNodes.getLength());
        }
    }
}

