package com.enterprise.saml.service;

import com.enterprise.saml.config.SamlProperties;
import org.springframework.stereotype.Service;

import java.io.ByteArrayOutputStream;
import java.time.Instant;
import java.util.Base64;
import java.util.UUID;
import java.util.zip.Deflater;
import java.util.zip.DeflaterOutputStream;

@Service
public class SamlRequestGenerator {

    private final SamlProperties samlProperties;

    public SamlRequestGenerator(SamlProperties samlProperties) {
        this.samlProperties = samlProperties;
    }

    public String generateAuthnRequest() throws Exception {
        String id = "_" + UUID.randomUUID().toString();
        String issueInstant = Instant.now().toString();

        String authnRequest = String.format(
            "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
            "<samlp:AuthnRequest xmlns:samlp=\"urn:oasis:names:tc:SAML:2.0:protocol\" " +
            "xmlns:saml=\"urn:oasis:names:tc:SAML:2.0:assertion\" " +
            "ID=\"%s\" " +
            "Version=\"2.0\" " +
            "IssueInstant=\"%s\" " +
            "Destination=\"%s\" " +
            "AssertionConsumerServiceURL=\"%s\" " +
            "ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\">" +
            "<saml:Issuer>%s</saml:Issuer>" +
            "<samlp:NameIDPolicy Format=\"urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress\" " +
            "AllowCreate=\"true\"/>" +
            "</samlp:AuthnRequest>",
            id, issueInstant, samlProperties.getIdpSsoUrl(),
            samlProperties.getAcsUrl(), samlProperties.getEntityId()
        );

        // Deflate and Base64 encode for HTTP-Redirect binding
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        DeflaterOutputStream deflaterStream = new DeflaterOutputStream(baos, deflater);
        deflaterStream.write(authnRequest.getBytes("UTF-8"));
        deflaterStream.close();

        return Base64.getEncoder().encodeToString(baos.toByteArray());
    }

    public String getIdpSsoUrl() {
        return samlProperties.getIdpSsoUrl();
    }
}

// ==================== Session Manager Service ====================

package com.enterprise.saml.service;

import com.enterprise.saml.model.SamlUserPrincipal;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import javax.servlet.http.HttpSession;
import java.util.List;
import java.util.Map;

@Service
public class SessionManager {
    private static final Logger logger = LoggerFactory.getLogger(SessionManager.class);

    public static final String SESSION_ATTR_PRINCIPAL = "SAML_PRINCIPAL";
    public static final String SESSION_ATTR_NAME_ID = "SAML_NAME_ID";
    public static final String SESSION_ATTR_SESSION_INDEX = "SAML_SESSION_INDEX";
    public static final String SESSION_ATTR_EMAIL = "SAML_USER_EMAIL";
    public static final String SESSION_ATTR_FIRST_NAME = "SAML_USER_FIRST_NAME";
    public static final String SESSION_ATTR_LAST_NAME = "SAML_USER_LAST_NAME";
    public static final String SESSION_ATTR_DISPLAY_NAME = "SAML_USER_DISPLAY_NAME";
    public static final String SESSION_ATTR_ROLES = "SAML_USER_ROLES";
    public static final String SESSION_ATTR_ATTRIBUTES = "SAML_USER_ATTRIBUTES";
    public static final String SESSION_ATTR_AUTH_TIME = "SAML_AUTH_TIME";
    public static final String SESSION_ATTR_ISSUER = "SAML_ISSUER";

    public void storeUserInSession(HttpSession session, SamlUserPrincipal principal) {
        // Store the full principal
        session.setAttribute(SESSION_ATTR_PRINCIPAL, principal);

        // Store individual attributes for easy access
        session.setAttribute(SESSION_ATTR_NAME_ID, principal.getNameId());
        session.setAttribute(SESSION_ATTR_SESSION_INDEX, principal.getSessionIndex());
        session.setAttribute(SESSION_ATTR_ISSUER, principal.getIssuer());

        if (principal.getAuthenticationInstant() != null) {
            session.setAttribute(SESSION_ATTR_AUTH_TIME, principal.getAuthenticationInstant().toString());
        }

        // Store common user attributes
        String email = principal.getEmail();
        if (email != null) {
            session.setAttribute(SESSION_ATTR_EMAIL, email);
        }

        String firstName = principal.getFirstName();
        if (firstName != null) {
            session.setAttribute(SESSION_ATTR_FIRST_NAME, firstName);
        }

        String lastName = principal.getLastName();
        if (lastName != null) {
            session.setAttribute(SESSION_ATTR_LAST_NAME, lastName);
        }

        // Build display name
        String displayName = buildDisplayName(firstName, lastName, principal.getNameId());
        session.setAttribute(SESSION_ATTR_DISPLAY_NAME, displayName);

        // Store roles
        List<String> roles = principal.getRoles();
        session.setAttribute(SESSION_ATTR_ROLES, roles);

        // Store all attributes map
        session.setAttribute(SESSION_ATTR_ATTRIBUTES, principal.getAttributes());

        // Store each individual SAML attribute with a prefix
        for (Map.Entry<String, List<String>> entry : principal.getAttributes().entrySet()) {
            String key = "SAML_ATTR_" + sanitizeAttributeName(entry.getKey());
            if (entry.getValue().size() == 1) {
                session.setAttribute(key, entry.getValue().get(0));
            } else {
                session.setAttribute(key, entry.getValue());
            }
        }

        logger.info("Stored SAML user attributes in session. User: {}, Session ID: {}",
            principal.getNameId(), session.getId());
    }

    public SamlUserPrincipal getPrincipalFromSession(HttpSession session) {
        return (SamlUserPrincipal) session.getAttribute(SESSION_ATTR_PRINCIPAL);
    }

    public void clearSession(HttpSession session) {
        session.invalidate();
        logger.info("Cleared SAML session");
    }

    private String buildDisplayName(String firstName, String lastName, String nameId) {
        StringBuilder sb = new StringBuilder();
        if (firstName != null) {
            sb.append(firstName);
        }
        if (lastName != null) {
            if (sb.length() > 0) sb.append(" ");
            sb.append(lastName);
        }
        if (sb.length() == 0) {
            sb.append(nameId);
        }
        return sb.toString();
    }

    private String sanitizeAttributeName(String name) {
        return name.replaceAll("[^a-zA-Z0-9_]", "_");
    }
}

// ==================== SAML Controller ====================

package com.enterprise.saml.controller;

import com.enterprise.saml.model.SamlUserPrincipal;
import com.enterprise.saml.security.SamlAuthenticationToken;
import com.enterprise.saml.service.SamlProcessingException;
import com.enterprise.saml.service.SamlRequestGenerator;
import com.enterprise.saml.service.SamlResponseParser;
import com.enterprise.saml.service.SessionManager;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;
import java.net.URLEncoder;

@Controller
public class SamlController {
    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    private final SamlResponseParser samlResponseParser;
    private final SamlRequestGenerator samlRequestGenerator;
    private final SessionManager sessionManager;

    public SamlController(SamlResponseParser samlResponseParser,
                          SamlRequestGenerator samlRequestGenerator,
                          SessionManager sessionManager) {
        this.samlResponseParser = samlResponseParser;
        this.samlRequestGenerator = samlRequestGenerator;
        this.sessionManager = sessionManager;
    }

    @GetMapping("/saml/login")
    public void initiateLogin(HttpServletResponse response) throws Exception {
        String samlRequest = samlRequestGenerator.generateAuthnRequest();
        String idpUrl = samlRequestGenerator.getIdpSsoUrl();
        String redirectUrl = idpUrl + "?SAMLRequest=" + URLEncoder.encode(samlRequest, "UTF-8");

        logger.info("Initiating SAML login, redirecting to IdP: {}", idpUrl);
        response.sendRedirect(redirectUrl);
    }

    @PostMapping("/saml/acs")
    public String assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request,
            HttpServletResponse response,
            Model model) {

        logger.info("Received SAML Response at ACS endpoint");

        try {
            // Parse and validate the SAML response
            SamlUserPrincipal principal = samlResponseParser.parseSamlResponse(samlResponse);

            // Create new session (invalidate old one to prevent session fixation)
            HttpSession oldSession = request.getSession(false);
            if (oldSession != null) {
                oldSession.invalidate();
            }
            HttpSession newSession = request.getSession(true);

            // Store user attributes in session
            sessionManager.storeUserInSession(newSession, principal);

            // Set Spring Security context
            SamlAuthenticationToken authToken = SamlAuthenticationToken.fromPrincipal(principal, samlResponse);
            SecurityContextHolder.getContext().setAuthentication(authToken);

            // Store security context in session
            newSession.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());

            logger.info("SAML authentication successful for user: {}", principal.getNameId());

            // Redirect to relay state or default page
            if (relayState != null && !relayState.isEmpty() && relayState.startsWith("/")) {
                return "redirect:" + relayState;
            }

            return "redirect:/dashboard";

        } catch (SamlProcessingException e) {
            logger.error("SAML authentication failed: {}", e.getMessage());
            model.addAttribute("error", "Authentication failed: " + e.getMessage());
            return "error/saml-error";
        }
    }

    @GetMapping("/saml/logout")
    public String logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            SamlUserPrincipal principal = sessionManager.getPrincipalFromSession(session);
            if (principal != null) {
                logger.info("Logging out SAML user: {}", principal.getNameId());
            }
            sessionManager.clearSession(session);
        }

        SecurityContextHolder.clearContext();
        return "redirect:/saml/login";
    }

    @GetMapping("/saml/metadata")
    @ResponseBody
    public String metadata() {
        // Return SP metadata for IdP configuration
        return generateSpMetadata();
    }

    private String generateSpMetadata() {
        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
            "<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\" " +
            "entityID=\"" + samlRequestGenerator.getIdpSsoUrl() + "\">" +
            "<md:SPSSODescriptor AuthnRequestsSigned=\"false\" " +
            "WantAssertionsSigned=\"true\" " +
            "protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">" +
            "<md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>" +
            "<md:AssertionConsumerService " +
            "Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" " +
            "Location=\"/saml/acs\" " +
            "index=\"0\" isDefault=\"true\"/>" +
            "</md:SPSSODescriptor>" +
            "</md:EntityDescriptor>";
    }
}

// ==================== Dashboard Controller ====================

package com.enterprise.saml.controller;

import com.enterprise.saml.model.SamlUserPrincipal;
import com.enterprise.saml.service.SessionManager;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import javax.servlet.http.HttpSession;

@Controller
public class DashboardController {

    private final SessionManager sessionManager;

    public DashboardController(SessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @GetMapping("/dashboard")
    public String dashboard(HttpSession session, Model model) {
        SamlUserPrincipal principal = sessionManager.getPrincipalFromSession(session);

        if (principal == null) {
            return "redirect:/saml/login";
        }

        model.addAttribute("user", principal);
        model.addAttribute("nameId", principal.getNameId());
        model.addAttribute("email", principal.getEmail());
        model.addAttribute("firstName", principal.getFirstName());
        model.addAttribute("lastName", principal.getLastName());
        model.addAttribute("roles", principal.getRoles());
        model.addAttribute("attributes", principal.getAttributes());
        model.addAttribute("sessionIndex", principal.getSessionIndex());
        model.addAttribute("authTime", principal.getAuthenticationInstant());
        model.addAttribute("issuer", principal.getIssuer());

        return "dashboard";
    }

    @GetMapping("/")
    public String home() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth != null && auth.isAuthenticated() && !"anonymousUser".equals(auth.getPrincipal())) {
            return "redirect:/dashboard";
        }
        return "redirect:/saml/login";
    }
}

// ==================== Security Configuration ====================

package com.enterprise.saml.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import org.springframework.security.web.csrf.CsrfFilter;
import org.springframework.security.web.csrf.CsrfTokenRepository;
import org.springframework.security.web.csrf.HttpSessionCsrfTokenRepository;

@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .authorizeRequests()
                .antMatchers("/saml/acs", "/saml/login", "/saml/metadata", "/saml/logout", "/error/**").permitAll()
                .antMatchers("/css/**", "/js/**", "/images/**").permitAll()
                .anyRequest().authenticated()
            .and()
            .csrf()
                .ignoringAntMatchers("/saml/acs") // SAML POST from IdP won't have CSRF token
                .csrfTokenRepository(csrfTokenRepository())
            .and()
            .logout()
                .logoutUrl("/saml/logout")
                .logoutSuccessUrl("/saml/login")
                .invalidateHttpSession(true)
                .deleteCookies("JSESSIONID")
            .and()
            .sessionManagement()
                .sessionFixation().newSession()
                .maximumSessions(1);
    }

    @Bean
    public CsrfTokenRepository csrfTokenRepository() {
        HttpSessionCsrfTokenRepository repository = new HttpSessionCsrfTokenRepository();
        repository.setHeaderName("X-CSRF-TOKEN");
        return repository;
    }
}

// ==================== SAML Authentication Filter ====================

package com.enterprise.saml.security;

import com.enterprise.saml.model.SamlUserPrincipal;
import com.enterprise.saml.service.SessionManager;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

@Component
public class SamlSessionAuthenticationFilter extends OncePerRequestFilter {

    private final SessionManager sessionManager;

    public SamlSessionAuthenticationFilter(SessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                     HttpServletResponse response,
                                     FilterChain filterChain) throws ServletException, IOException {

        // Check if already authenticated in SecurityContext
        if (SecurityContextHolder.getContext().getAuthentication() != null &&
            SecurityContextHolder.getContext().getAuthentication().isAuthenticated() &&
            !"anonymousUser".equals(SecurityContextHolder.getContext().getAuthentication().getPrincipal())) {
            filterChain.doFilter(request, response);
            return;
        }

        // Try to restore authentication from session
        HttpSession session = request.getSession(false);
        if (session != null) {
            SamlUserPrincipal principal = sessionManager.getPrincipalFromSession(session);
            if (principal != null) {
                SamlAuthenticationToken token = SamlAuthenticationToken.fromPrincipal(principal, null);
                SecurityContextHolder.getContext().setAuthentication(token);
            }
        }

        filterChain.doFilter(request, response);
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        String path = request.getRequestURI();
        return path.startsWith("/saml/") ||
               path.startsWith("/css/") ||
               path.startsWith("/js/") ||
               path.startsWith("/images/") ||
               path.startsWith("/error/");
    }
}

// ==================== Filter Registration ====================

package com.enterprise.saml.config;

import com.enterprise.saml.security.SamlSessionAuthenticationFilter;
import org.springframework.boot.web.servlet.FilterRegistrationBean;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class FilterConfig {

    @Bean
    public FilterRegistrationBean<SamlSessionAuthenticationFilter> samlFilterRegistration(
            SamlSessionAuthenticationFilter filter) {
        FilterRegistrationBean<SamlSessionAuthenticationFilter> registration = new FilterRegistrationBean<>();
        registration.setFilter(filter);
        registration.addUrlPatterns("/*");
        registration.setOrder(1);
        return registration;
    }
}

