package com.enterprise.saml.controller;

import com.enterprise.saml.model.SamlUserPrincipal;
import com.enterprise.saml.service.SessionManager;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import javax.servlet.http.HttpSession;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class UserInfoController {

    private final SessionManager sessionManager;

    public UserInfoController(SessionManager sessionManager) {
        this.sessionManager = sessionManager;
    }

    @GetMapping("/userinfo")
    public ResponseEntity<Map<String, Object>> getUserInfo(HttpSession session) {
        SamlUserPrincipal principal = sessionManager.getPrincipalFromSession(session);

        if (principal == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> userInfo = new HashMap<>();
        userInfo.put("nameId", principal.getNameId());
        userInfo.put("nameIdFormat", principal.getNameIdFormat());
        userInfo.put("email", principal.getEmail());
        userInfo.put("firstName", principal.getFirstName());
        userInfo.put("lastName", principal.getLastName());
        userInfo.put("roles", principal.getRoles());
        userInfo.put("sessionIndex", principal.getSessionIndex());
        userInfo.put("authenticationInstant", principal.getAuthenticationInstant());
        userInfo.put("issuer", principal.getIssuer());
        userInfo.put("attributes", principal.getAttributes());

        return ResponseEntity.ok(userInfo);
    }

    @GetMapping("/session/attributes")
    public ResponseEntity<Map<String, Object>> getSessionAttributes(HttpSession session) {
        Map<String, Object> sessionAttributes = new HashMap<>();

        sessionAttributes.put("nameId", session.getAttribute(SessionManager.SESSION_ATTR_NAME_ID));
        sessionAttributes.put("email", session.getAttribute(SessionManager.SESSION_ATTR_EMAIL));
        sessionAttributes.put("firstName", session.getAttribute(SessionManager.SESSION_ATTR_FIRST_NAME));
        sessionAttributes.put("lastName", session.getAttribute(SessionManager.SESSION_ATTR_LAST_NAME));
        sessionAttributes.put("displayName", session.getAttribute(SessionManager.SESSION_ATTR_DISPLAY_NAME));
        sessionAttributes.put("roles", session.getAttribute(SessionManager.SESSION_ATTR_ROLES));
        sessionAttributes.put("authTime", session.getAttribute(SessionManager.SESSION_ATTR_AUTH_TIME));
        sessionAttributes.put("issuer", session.getAttribute(SessionManager.SESSION_ATTR_ISSUER));
        sessionAttributes.put("sessionIndex", session.getAttribute(SessionManager.SESSION_ATTR_SESSION_INDEX));

        return ResponseEntity.ok(sessionAttributes);
    }
}

